sp_widget.client_script:
api.controller = function($location) {
    /* widget controller */
    var c = this;
    c.selectedPeriod = '';
		c.selectedYear = ''; 
    c.selectedUser = '';
    c.selectedStatus = '';
    c.showDetailModal = false;
    c.showDisputeModal = false;
    c.currentStatement = null;
    c.disputeData = {
        reason: '',
        comments: ''
    };

		/* Get display name for selected user */
		/* Get display name for selected user */
		c.getSelectedUserName = function() {
				if (!c.selectedUser || !c.data.users) 
						return "All Team Members";

				for (var i = 0; i < c.data.users.length; i++) {
						if (c.data.users[i].id === c.selectedUser) {
								return c.data.users[i].name;
						}
				}
				return "All Team Members";
		};

		/* Get display name for selected period */
		c.getSelectedPeriodName = function() {
				if (!c.selectedPeriod || !c.data.fiscalPeriods)
						return "";

				for (var i = 0; i < c.data.fiscalPeriods.length; i++) {
						if (c.data.fiscalPeriods[i].id === c.selectedPeriod) {
								return c.data.fiscalPeriods[i].name;
						}
				}
				return "";
		};

    c.loadStatements = function() {
    c.currentPage = 1;
    c.data.period = c.selectedPeriod;
		c.data.year   = c.selectedYear;
    c.data.user = c.selectedUser;
    c.data.status = c.selectedStatus;

    // Trigger the server script to run again with these new values
    c.server.update().then(function(response) {
        // The table will now refresh with the filtered data
        console.log("Found " + c.data.statements.length + " statements.");
				});
		};

    c.viewStatement = function(statementId) {

			window.location = '?id=incentive_statement_view&statement_id=' + statementId;
        /*c.server.get({
            action: 'get_statement_detail',
            statement_id: statementId
        }).then(function(response) {
            c.currentStatement = response.data.statement;
            c.showDetailModal = true;
        });*/
    };

    c.closeDetailModal = function() {
        c.showDetailModal = false;
        c.currentStatement = null;
    };

    c.openDisputeModal = function(statement) {
        c.currentStatement = statement;
        c.disputeData = {
            reason: '',
            comments: ''
        };
        c.showDisputeModal = true;
    };

    c.closeDisputeModal = function() {
        c.showDisputeModal = false;
        c.disputeData = {
            reason: '',
            comments: ''
        };
    };

    c.submitDispute = function() {
        if (!c.disputeData.reason || !c.disputeData.comments) {
            alert('Please fill in all fields');
            return;
        }

        c.server.update({
            action: 'submit_dispute',
            statement_id: c.currentStatement.id,
            reason: c.disputeData.reason,
            comments: c.disputeData.comments
        }).then(function(response) {
            if (response.data.success) {
                c.closeDisputeModal();
                c.loadStatements();
                alert('Dispute submitted successfully');
            }
        });
    };

    c.downloadPDF = function() {

				var url='/api/x_incent/statement/' + c.currentStatement.id + '/pdf';
				$location.url(url);
    };

    c.generateStatements = function() {

			var url ='?id=incentnow_generate_statements';
			$location.url(url);
    };

		// Pagination
		c.currentPage = 1;
		c.pageSize = 10; // rows per page

		c.getPaginatedStatements = function() {
				if (!c.data.statements) return [];

				var start = (c.currentPage - 1) * c.pageSize;
				var end = start + c.pageSize;

				return c.data.statements.slice(start, end);
		};

		c.totalPages = function() {
				if (!c.data.statements || c.data.statements.length === 0) return 0;
				return Math.ceil(c.data.statements.length / c.pageSize);
		};

		c.nextPage = function() {
				if (c.currentPage < c.totalPages()) {
						c.currentPage++;
				}
		};

		c.prevPage = function() {
				if (c.currentPage > 1) {
						c.currentPage--;
				}
		};

	 /* Formatting currency without $scope */
    this.formatCurrency = function(num) {
        if (!num) return "$0";
        return "$" + Number(num).toLocaleString();
    };
};

