sp_widget.script:
(function() {
    /* populate the 'data' object */
    /* e.g., data.table = $sp.getValue('table'); */
    // Check if user is admin
		data.tableWidget=$sp.getWidget('incentnow-table-widget',{ table: 'x_ctans_incentnow_incentive_statement',view:'',viewperiod:'false'});
    data.isAdmin =
    gs.hasRole('x_ctans_incentnow.admin') ||
    gs.hasRole('x_ctans_incentnow.manager') ||
		gs.hasRole('x_ctans_incentnow.business_group_executive') ||
		gs.hasRole('x_ctans_incentnow.business_group_admin') ||
		gs.hasRole('x_ctans_incentnow.org_executive');
		//data.isAdmin = gs.hasRole('snc_internal'); 
    // Get fiscal periods
    data.fiscalYears = [];
		data.isIncentBusinessGroupAdmin = gs.hasRole('x_ctans_incentnow.business_group_admin') || gs.hasRole('x_ctans_incentnow.admin');


		var yearMap = {};
		var yearGR = new GlideRecordSecure('x_ctans_incentnow_fiscal_calendar');
		yearGR.orderBy('fiscal_year_name');
		yearGR.query();

		while (yearGR.next()) {

				var yearName = yearGR.getValue('fiscal_year_name');
				var yearId = yearGR.getUniqueValue(); //  important

				if (yearName && !yearMap[yearId]) {
						yearMap[yearId] = true;

						data.fiscalYears.push({
								id: yearId,     // use sys_id
								name: yearName  // display
						});
				}
		}
		var MONTH_ORDER_FULL = [
			"January","February","March","April","May","June",
			"July","August","September","October","November","December"
		];

		data.fiscalPeriods = [];

		var periodGR = new GlideRecordSecure('x_ctans_incentnow_fiscal_period');

		if (input && input.year) {
				periodGR.addQuery('fiscal_year', input.year); 
		}

		//periodGR.addQuery('period_type', 'month');
		periodGR.query();

		var tempPeriods = [];

		while (periodGR.next()) {
				tempPeriods.push({
						id: periodGR.getUniqueValue(),
						name: periodGR.getValue('period_name')
				});
		}

		// Sort properly
		tempPeriods.sort(function(a, b) {
				var monthA = a.name.split(" ")[0];
				var monthB = b.name.split(" ")[0];

				return MONTH_ORDER_FULL.indexOf(monthA) - MONTH_ORDER_FULL.indexOf(monthB);
		});

		data.fiscalPeriods = tempPeriods;

    // Get users (for admin)
    data.users = [];
    if (data.isAdmin) {
        var userGR = new GlideRecordSecure('x_ctans_incentnow_user_profile');
        userGR.addActiveQuery();
        userGR.orderBy('name');
        userGR.query();
        while (userGR.next()) {
            data.users.push({
                id: userGR.getUniqueValue(),
                name: userGR.getValue('name')
            });
        }
    }



    // Get statements
		data.statements = [];
		var stmtGR = new GlideRecordSecure('x_ctans_incentnow_incentive_statement');

  // Status Filter
	stmtGR.addQuery('status', 'statement_generated');

		if (input) {

				if (input.year && input.year != "") {
						stmtGR.addQuery('fiscal_year', input.year);
				}
				// 1. Period Filter
				if (input.period && input.period != "") {
						stmtGR.addQuery('fiscal_period', input.period);
				}

				// 2. Team Member Filter (Dynamic)
				// input.user contains the sys_id of the record from x_ctans_incentnow_sales_user
				if (input.user && input.user != "") {

						stmtGR.addQuery('user', input.user);
				}

		} else if (!data.isAdmin) {

				var profileGR = new GlideRecordSecure('x_ctans_incentnow_user_profile');
				profileGR.addQuery('user', gs.getUserID()); // adjust field name if needed
				profileGR.setLimit(1);
				profileGR.query();

				if (profileGR.next()) {
						stmtGR.addQuery('user', profileGR.getUniqueValue());
				}
		}

		stmtGR.orderByDesc('sys_created_on');
		stmtGR.query();

		//gs.addInfoMessage(stmtGR.getEncodedQuery());

		while (stmtGR.next()) {
				var totalComm = parseFloat(stmtGR.getValue('total_commission') || 0);
				var userEmail = '';
					if (stmtGR.getValue('user')) {
							var userGR = new GlideRecordSecure('sys_user');
							if (userGR.get(stmtGR.getValue('user'))) {
									userEmail = userGR.getValue('email') || '';
							}
					}

				data.statements.push({
						id: stmtGR.getUniqueValue(),
						userName: stmtGR.getDisplayValue('user'), // Shows the 'name' from the User table automatically
						//userEmail: stmtGR.user ? stmtGR.user.email.toString() : '',
						userEmail: userEmail,
						periodName: stmtGR.getDisplayValue('fiscal_period'),
						generatedDate: stmtGR.getDisplayValue('sys_updated_on'),
						totalCommission: totalComm,
						totalCommissionDisplay: totalComm.toFixed(2),
						status: stmtGR.getDisplayValue('status')

				});
		}

	// commission rule breakdown --------------------------
		data.ruleDetails = {};
	// Create GlideRecord for incentive statements
	var recGR = new GlideRecordSecure('x_ctans_incentnow_incentive_statement');


  // Status Filter
	recGR.addQuery('status', 'statement_generated');	

	// Apply filters if input exists
	if (input) {
			// 1. Period Filter
			if (input.period && input.period != "") {
					recGR.addQuery('fiscal_period', input.period);
			}

			// 2. Team Member Filter
			if (input.user && input.user != "") {
					recGR.addQuery('user', input.user);
			}


	} else if (!data.isAdmin) {
			// Initial load for non-admins
			recGR.addQuery('user', gs.getUserID());
	}

	// Sort by generated date (latest first)
	recGR.orderByDesc('u_generated_date');
	recGR.query();

	// Pick the first record if available
	if (recGR.next()) {
			var rawJson = recGR.getValue('payout_results'); // JSON field

			if (rawJson) {
					try {
							data.ruleDetails = JSON.parse(rawJson);
					} catch (e) {
							data.ruleDetails = { error: "Invalid JSON format" };
					}
			}
	}

    // Handle get statement detail
    if (input && input.action === 'get_statement_detail') {
        var detailGR = new GlideRecordSecure('x_ctans_incentnow_incentive_statement');
        if (detailGR.get(input.statement_id)) {
            // Get user info
            var userName = '';
            var userEmail = '';
            if (detailGR.user.toString()) {
                var u = new GlideRecordSecure('x_ctans_incentnow_user_profile');
                if (u.get(detailGR.user.toString())) {
                    userName = u.getValue('name');
                    userEmail = u.getValue('email');
                }
            }

            // Get period name
            var periodName = '';
            if (detailGR.fiscal_period.toString()) {
                var p = new GlideRecordSecure('x_ctans_incentnow_fiscal_period');
                if (p.get(detailGR.fiscal_period.toString())) {
                    periodName = p.getValue('u_name');
                }
            }

            // Get line items
            var lineItems = [];
            var lineGR = new GlideRecordSecure('x_1776231_incent_0_u_statement_line_item');
            lineGR.addQuery('u_statement', input.statement_id);
            lineGR.orderBy('u_order');
            lineGR.query();
            while (lineGR.next()) {
                lineItems.push({
                    ruleName: lineGR.getValue('u_payout_rule_name'),
                    calculation: lineGR.getValue('u_calculation_detail'),
                    amount: parseFloat(lineGR.getValue('u_amount') || 0),
                    amountDisplay: (parseFloat(lineGR.getValue('u_amount') || 0)).toFixed(2)
                });
            }

            data.statement = {
                id: detailGR.getUniqueValue(),
                userName: userName,
                userEmail: userEmail,
                periodName: periodName,
                totalCommission: parseFloat(detailGR.getValue('u_total_commission') || 0),
                totalCommissionDisplay: (parseFloat(detailGR.getValue('u_total_commission') || 0)).toFixed(2),
                status: detailGR.getValue('u_status'),
                lineItems: lineItems,
                disputeReason: detailGR.getValue('u_dispute_reason'),
                disputeComments: detailGR.getValue('u_dispute_comments'),
                disputeDate: detailGR.getValue('u_dispute_date')
            };
        }
    }

    // Handle submit dispute
    if (input && input.action === 'submit_dispute') {
        var disputeGR = new GlideRecordSecure('x_ctans_incentnow_incentive_statement');
        if (disputeGR.get(input.statement_id)) {
            disputeGR.setValue('u_status', 'disputed');
            disputeGR.setValue('u_dispute_reason', input.reason);
            disputeGR.setValue('u_dispute_comments', input.comments);
            disputeGR.setValue('u_dispute_date', new GlideDateTime());
            disputeGR.update();
            data.success = true;
        }
    }

    // Handle generate statements
    if (input && input.action === 'generate_statements' && data.isAdmin) {

        var generator = new IncentiveStatementGenerator();

        var planGR = new GlideRecordSecure('x_ctans_incentnow_plan');
        planGR.addQuery('u_status', 'active');
        planGR.setLimit(1);
        planGR.query();

        if (planGR.next()) {

            var result;

            if (input.user) {

                // Generate for single user
                result = generator.generateUserStatement(
                    planGR.getUniqueValue(),
                    input.period,
                    input.user
                );

                data.count = result.success;

            } else {

                // Generate for all users
                result = generator.generateBulkStatements(
                    planGR.getUniqueValue(),
                    input.period
                );

                data.count = result.success;

            }

            data.success = true;

        }

    }
})();
